const { target_host, lxc_id, vm_id, proxmox_host, session_id } = $('📥 Input').first().json;
if (!target_host) throw new Error('target_host erforderlich');
const check_cmd = 'apt list --upgradable 2>/dev/null | grep -v "^Listing" | head -50';
return { target_host, lxc_id: lxc_id || null, vm_id: vm_id || null,
  proxmox_host: proxmox_host || '10.1.1.100', command: check_cmd,
  session_id: session_id || require('crypto').randomUUID() };

const input = $('📥 Input').first().json;
const ssh = $('💻 SUB: Check Updates').first().json;
const packages = ssh?.data?.stdout || '(keine Updates)';
return { prompt: `System ${input.target_host} – verfügbare Updates:\n\n${packages}\n\nBewerte: Sicherheits-Updates, kritische Pakete, Risiken. Soll das Update durchgeführt werden? Antworte als JSON: {should_update(bool), risk_level(low/medium/high), critical_packages:[], reason, update_command}`,
  model: 'claude-sonnet-4-6', max_tokens: 800, session_id: input.session_id };

const input = $('📥 Input').first().json;
const plan = $('🤖 SUB: Claude Plan').first().json;
const r = typeof plan.response === 'string' ? JSON.parse(plan.response) : plan.response || {};
if (!r.should_update) return { exit_code: 'success', session_id: input.session_id,
  data: { target_host: input.target_host, updated: false, reason: r.reason }, timestamp: new Date().toISOString() };
return { target_host: input.target_host, command: r.update_command || 'apt-get upgrade -y',
  session_id: input.session_id, plan: r };

const input = $('🔧 Execute or Skip').first().json;
const ssh = $input.first().json;
return { exit_code: 'success', session_id: input.session_id,
  data: { target_host: input.target_host, updated: !!input.plan,
    result: ssh?.data?.stdout || '(übersprungen)', plan: input.plan || null },
  timestamp: new Date().toISOString() };
